  1→// @tautology-skip: E2E tests exercise production code via real protocol connections
  2→/**
  3→ * E2E integration tests for MCP Server with real protocol clients
  4→ * Issue #414: MCP server E2E tests with real protocol client
  5→ *
  6→ * Tests the full path: Real MCP Client → protocol → sequant serve → handler → response
  7→ * Complements existing unit tests (src/mcp/*.test.ts) and integration tests
  8→ * (mcp-serve*.integration.test.ts) which use mocks or InMemoryTransport.
  9→ */
 10→
 11→import { describe, it, expect, afterAll, afterEach, beforeAll } from "vitest";
 12→import { type ChildProcess } from "child_process";
 13→import * as fs from "fs";
 14→import * as path from "path";
 15→import * as http from "http";
 16→import * as net from "net";
 17→import * as os from "os";
 18→
 19→// AC-9: SDK optional guard — skip cleanly when SDK not installed (#396)
 20→const mcpSdkAvailable = await import("@modelcontextprotocol/sdk/server/mcp.js")
 21→  .then(() => true)
 22→  .catch(() => false);
 23→
 24→const TEST_DIR = path.join(
 25→  os.tmpdir(),
 26→  `sequant-mcp-e2e-${process.pid}-${Date.now()}`,
 27→);
 28→
 29→// Track clients for cleanup (StdioClientTransport spawns internal processes)
 30→// eslint-disable-next-line @typescript-eslint/no-explicit-any
 31→const activeClients: any[] = [];
 32→
 33→// Track manually spawned server processes for cleanup
 34→const spawnedProcesses: ChildProcess[] = [];
 35→
 36→function getAvailablePort(): Promise<number> {
 37→  return new Promise((resolve) => {
 38→    const server = net.createServer();
 39→    server.listen(0, () => {
 40→      const addr = server.address() as net.AddressInfo;
 41→      server.close(() => resolve(addr.port));
 42→    });
 43→  });
 44→}
 45→
 46→function waitForServer(port: number, timeoutMs = 15000): Promise<void> {
 47→  return new Promise((resolve, reject) => {
 48→    const start = Date.now();
 49→    const check = () => {
 50→      http
 51→        .get(`http://localhost:${port}/health`, (res) => {
 52→          if (res.statusCode === 200) {
 53→            resolve();
 54→          } else {
 55→            retry();
 56→          }
 57→        })
 58→        .on("error", retry);
 59→    };
 60→    const retry = () => {
 61→      if (Date.now() - start > timeoutMs) {
 62→        reject(
 63→          new Error(
 64→            `Server on port ${port} did not start within ${timeoutMs}ms`,
 65→          ),
 66→        );
 67→      } else {
 68→        setTimeout(check, 200);
 69→      }
 70→    };
 71→    check();
 72→  });
 73→}
 74→
 75→function httpGet(url: string): Promise<{
 76→  status: number;
 77→  body: string;
 78→  headers: http.IncomingHttpHeaders;
 79→}> {
 80→  return new Promise((resolve, reject) => {
 81→    http
 82→      .get(url, (res) => {
 83→        let body = "";
 84→        res.on("data", (chunk: string) => (body += chunk));
 85→        res.on("end", () =>
 86→          resolve({ status: res.statusCode || 0, body, headers: res.headers }),
 87→        );
 88→      })
 89→      .on("error", reject);
 90→  });
 91→}
 92→
 93→function killProcessGroup(child: ChildProcess, signal: NodeJS.Signals) {
 94→  try {
 95→    process.kill(-child.pid!, signal);
 96→  } catch {
 97→    if (!child.killed) {
 98→      child.kill(signal);
 99→    }
100→  }
101→}
102→
103→function spawnServe(args: string[]): ChildProcess {
104→  // Inline import to avoid top-level side effects when SDK missing
105→  const { spawn } = require("child_process");
106→  const binPath = path.resolve(__dirname, "../../bin/cli.ts");
107→  const child = spawn("npx", ["tsx", binPath, "serve", ...args], {
108→    stdio: ["pipe", "pipe", "pipe"],
109→    env: { ...process.env },
110→    detached: true,
111→  });
112→  spawnedProcesses.push(child);
113→  return child;
114→}
115→
116→// AC-10: Use temp directories for isolation — no writes to real .sequant/
117→beforeAll(() => {
118→  fs.mkdirSync(TEST_DIR, { recursive: true });
119→});
120→
121→afterEach(async () => {
122→  // Close any active SDK clients
123→  for (const client of activeClients) {
124→    try {
125→      await client.close();
126→    } catch {
127→      /* client may already be disconnected */
128→    }
129→  }
130→  activeClients.length = 0;
131→
132→  // Kill any manually spawned server processes
133→  for (const proc of spawnedProcesses) {
134→    killProcessGroup(proc, "SIGKILL");
135→  }
136→  spawnedProcesses.length = 0;
137→});
138→
139→afterAll(() => {
140→  if (fs.existsSync(TEST_DIR)) {
141→    fs.rmSync(TEST_DIR, { recursive: true, force: true });
142→  }
143→});
144→
145→describe.skipIf(!mcpSdkAvailable)("MCP Server — E2E (#414)", () => {
146→  // ─── Helpers ───────────────────────────────────────────────────────
147→
148→  /** Create an SDK client connected via stdio transport */
149→  async function createStdioClient() {
150→    const { Client } =
151→      await import("@modelcontextprotocol/sdk/client/index.js");
152→    const { StdioClientTransport } =
153→      await import("@modelcontextprotocol/sdk/client/stdio.js");
154→
