172→    const { SSEClientTransport } =
173→      await import("@modelcontextprotocol/sdk/client/sse.js");
174→
175→    const transport = new SSEClientTransport(
176→      new URL(`http://localhost:${port}/sse`),
177→    );
178→    const client = new Client({ name: "e2e-sse", version: "1.0.0" });
179→    await client.connect(transport);
180→    activeClients.push(client);
181→    return client;
182→  }
183→
184→  // ─── Stdio E2E ─────────────────────────────────────────────────────
185→
186→  describe("Stdio E2E", () => {
187→    // AC-1: Tool discovery via real stdio protocol
188→    it("AC-1: should discover all tools via stdio protocol", async () => {
189→      const client = await createStdioClient();
190→
191→      const { tools } = await client.listTools();
192→      const toolNames = tools.map((t: { name: string }) => t.name).sort();
193→      expect(toolNames).toEqual([
194→        "sequant_logs",
