198→
199→      // Each tool should have a valid input schema
200→      for (const tool of tools) {
201→        expect(tool.inputSchema).toBeDefined();
202→        expect(tool.inputSchema.type).toBe("object");
203→      }
204→    }, 20000);
205→
206→    // AC-2: Resource discovery via real stdio protocol
207→    it("AC-2: should discover resources via stdio protocol", async () => {
208→      const client = await createStdioClient();
209→
210→      const { resources } = await client.listResources();
211→      const uris = resources.map((r: { uri: string }) => r.uri).sort();
212→      expect(uris).toEqual(["sequant://config", "sequant://state"]);
213→    }, 20000);
214→
215→    // AC-3: Tool call round-trip via real stdio protocol
216→    it("AC-3: should round-trip sequant_status call via stdio", async () => {
217→      const client = await createStdioClient();
218→
219→      const result = await client.callTool({
220→        name: "sequant_status",
221→        arguments: { issue: 99999 },
222→      });
223→
224→      // Should get a well-formed MCP response (not a protocol error)
225→      expect(result).toBeDefined();
226→      expect(result.content).toBeDefined();
227→      expect(Array.isArray(result.content)).toBe(true);
228→      expect(result.content.length).toBeGreaterThan(0);
229→
230→      // Response should contain parseable JSON with not_tracked status
231→      const textContent = result.content.find(
232→        (c: { type: string }) => c.type === "text",
233→      );
234→      expect(textContent).toBeDefined();
235→      const data = JSON.parse(textContent.text);
236→      expect(data.status).toBe("not_tracked");
237→    }, 20000);
238→
239→    // AC-4: Resource read round-trip via real stdio protocol
240→    it("AC-4: should round-trip sequant://config read via stdio", async () => {
241→      const client = await createStdioClient();
242→
243→      const result = await client.readResource({
244→        uri: "sequant://config",
245→      });
246→
247→      // Should get valid content without protocol error
248→      expect(result).toBeDefined();
249→      expect(result.contents).toBeDefined();
250→      expect(Array.isArray(result.contents)).toBe(true);
251→      expect(result.contents.length).toBeGreaterThan(0);
252→
253→      const content = result.contents[0];
254→      expect(content.uri).toBe("sequant://config");
255→      expect(typeof content.text).toBe("string");
256→
257→      // Content should be parseable JSON (settings or default)
258→      expect(() => JSON.parse(content.text as string)).not.toThrow();
259→    }, 20000);
260→  });
261→
262→  // ─── SSE E2E ───────────────────────────────────────────────────────
263→
264→  describe("SSE E2E", () => {
265→    // AC-5: SSE client connection and tool call via SDK
266→    it("AC-5: should connect SDK client and call tool via SSE", async () => {
267→      const port = await getAvailablePort();
268→      spawnServe(["--transport", "sse", "--port", String(port)]);
