 43→function waitForServer(port: number, timeoutMs = 10000): Promise<void> {
 44→  return new Promise((resolve, reject) => {
 45→    const start = Date.now();
 46→    const check = () => {
 47→      http
 48→        .get(`http://localhost:${port}/health`, (res) => {
 49→          if (res.statusCode === 200) {
 50→            resolve();
 51→          } else {
 52→            retry();
 53→          }
 54→        })
 55→        .on("error", retry);
 56→    };
 57→    const retry = () => {
 58→      if (Date.now() - start > timeoutMs) {
 59→        reject(
 60→          new Error(
 61→            `Server on port ${port} did not start within ${timeoutMs}ms`,
 62→          ),
 63→        );
 64→      } else {
 65→        setTimeout(check, 200);
 66→      }
 67→    };
 68→    check();
 69→  });
 70→}
 71→
 72→function httpGet(url: string): Promise<{
 73→  status: number;
 74→  body: string;
 75→  headers: http.IncomingHttpHeaders;
 76→}> {
 77→  return new Promise((resolve, reject) => {
 78→    http
 79→      .get(url, (res) => {
 80→        let body = "";
 81→        res.on("data", (chunk) => (body += chunk));
 82→        res.on("end", () =>
 83→          resolve({ status: res.statusCode || 0, body, headers: res.headers }),
 84→        );
 85→      })
 86→      .on("error", reject);
 87→  });
 88→}
