 90→function killProcessGroup(child: ChildProcess, signal: NodeJS.Signals) {
 91→  try {
 92→    // Send signal to the entire process group (negative PID)
 93→    // This mirrors how terminals deliver signals (e.g., Ctrl+C sends SIGINT to the group)
 94→    process.kill(-child.pid!, signal);
 95→  } catch {
 96→    // Process group may already be gone — fall back to direct kill
 97→    if (!child.killed) {
 98→      child.kill(signal);
 99→    }
100→  }
101→}
