  1→/**
  2→ * sequant serve - Start MCP server
  3→ *
  4→ * Exposes Sequant workflow orchestration as tools and resources
  5→ * over the Model Context Protocol (MCP).
  6→ *
  7→ * Supports stdio (default) and SSE transports.
  8→ */
  9→
 10→import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
 11→import { SSEServerTransport } from "@modelcontextprotocol/sdk/server/sse.js";
 12→import {
 13→  createServer as createHttpServer,
 14→  type IncomingMessage,
 15→  type ServerResponse,
 16→} from "http";
 17→import { createServer } from "../mcp/server.js";
 18→import { getVersion } from "../lib/version.js";
 19→
 20→export interface ServeOptions {
 21→  transport?: "stdio" | "sse";
 22→  port?: number;
 23→}
 24→
 25→export async function serveCommand(options: ServeOptions): Promise<void> {
 26→  const version = getVersion();
 27→  const server = createServer(version);
 28→  const transportType = options.transport || "stdio";
 29→
 30→  if (transportType === "sse") {
 31→    await startSSE(server, options.port || 3100);
 32→  } else {
 33→    await startStdio(server);
 34→  }
 35→}
 36→
 37→async function startStdio(
 38→  server: ReturnType<typeof createServer>,
 39→): Promise<void> {
 40→  const transport = new StdioServerTransport();
 41→
 42→  // Handle graceful shutdown
 43→  const shutdown = async () => {
 44→    await server.close();
 45→    process.exit(0);
 46→  };
 47→
 48→  process.on("SIGINT", shutdown);
 49→  process.on("SIGTERM", shutdown);
 50→
 51→  await server.connect(transport);
 52→
 53→  // Write startup info to stderr (stdout is for MCP protocol)
 54→  process.stderr.write(`Sequant MCP server started (stdio)\n`);
 55→}
 56→
 57→async function startSSE(
 58→  server: ReturnType<typeof createServer>,
 59→  port: number,
 60→): Promise<void> {
 61→  let sseTransport: SSEServerTransport | null = null;
 62→  let clientConnected = false;
 63→
 64→  const httpServer = createHttpServer(
 65→    async (req: IncomingMessage, res: ServerResponse) => {
 66→      const url = new URL(req.url || "/", `http://localhost:${port}`);
 67→
 68→      if (url.pathname === "/sse" && req.method === "GET") {
 69→        // Reject if a client is already connected
 70→        if (clientConnected) {
 71→          res.writeHead(409, { "Content-Type": "application/json" });
 72→          res.end(
 73→            JSON.stringify({
 74→              error: "conflict",
 75→              message: "Another SSE client is already connected",
 76→            }),
 77→          );
 78→          return;
 79→        }
 80→
 81→        // SSE endpoint - create transport and connect
 82→        sseTransport = new SSEServerTransport("/messages", res);
 83→        clientConnected = true;
 84→
 85→        // Clean up on client disconnect
 86→        res.on("close", () => {
 87→          clientConnected = false;
 88→          sseTransport = null;
 89→        });
 90→
 91→        try {
 92→          await server.connect(sseTransport);
 93→        } catch {
 94→          clientConnected = false;
 95→          sseTransport = null;
 96→          if (!res.headersSent) {
 97→            res.writeHead(500, { "Content-Type": "application/json" });
 98→            res.end(
 99→              JSON.stringify({
100→                error: "connection_failed",
101→                message: "Failed to establish MCP transport connection",
102→              }),
103→            );
104→          }
105→        }
106→      } else if (
107→        url.pathname === "/messages" &&
108→        req.method === "POST" &&
109→        sseTransport
110→      ) {
111→        // Message endpoint for client-to-server communication
112→        await sseTransport.handlePostMessage(req, res);
113→      } else if (url.pathname === "/health" && req.method === "GET") {
114→        res.writeHead(200, { "Content-Type": "application/json" });
115→        res.end(
116→          JSON.stringify({
117→            status: "ok",
118→            transport: "sse",
119→            connected: clientConnected,
120→          }),
121→        );
122→      } else {
123→        res.writeHead(404);
124→        res.end("Not found");
125→      }
126→    },
127→  );
128→
129→  // Handle graceful shutdown
130→  const shutdown = async () => {
131→    await server.close();
132→    httpServer.close();
133→    process.exit(0);
134→  };
135→
136→  process.on("SIGINT", shutdown);
137→  process.on("SIGTERM", shutdown);
138→
139→  httpServer.listen(port, "127.0.0.1", () => {
140→    console.log(`Sequant MCP server started (SSE) on 127.0.0.1:${port}`);
141→    console.log(`  SSE endpoint: http://127.0.0.1:${port}/sse`);
142→    console.log(`  Health check: http://127.0.0.1:${port}/health`);
143→  });
144→}
